import React from 'react';

// material-ui
import { styled } from '@mui/material/styles';
import Button from '@mui/material/Button';
import ClickAwayListener from '@mui/material/ClickAwayListener';
import Fab from '@mui/material/Fab';
import Fade from '@mui/material/Fade';
import Grid from '@mui/material/Grid';
import IconButton from '@mui/material/IconButton';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';
import Zoom from '@mui/material/Zoom';
import MuiTooltip, { tooltipClasses } from '@mui/material/Tooltip';

// project imports
import MainCard from 'ui-component/cards/MainCard';
import { gridSpacing } from 'store/constant';

// assets
import DeleteIcon from '@mui/icons-material/Delete';
import AddIcon from '@mui/icons-material/Add';

// tooltip customization
const LightTooltip = styled(({ className, ...other }) => <MuiTooltip {...other} classes={{ popper: className }} />)(({ theme }) => ({
  [`& .${tooltipClasses.tooltip}`]: {
    backgroundColor: theme.vars.palette.common.white,
    color: 'rgba(0, 0, 0, 0.87)',
    boxShadow: theme.shadows[1],
    fontSize: 11
  }
}));

const BootstrapTooltip = styled(({ className, ...other }) => <MuiTooltip {...other} arrow classes={{ popper: className }} />)(
  ({ theme }) => ({
    [`& .${tooltipClasses.arrow}`]: {
      color: 'common.black',
      ...theme.applyStyles('dark', { color: 'common.white' })
    },
    [`& .${tooltipClasses.tooltip}`]: {
      backgroundColor: 'common.black',
      ...theme.applyStyles('dark', { backgroundColor: 'common.white' })
    }
  })
);

const HtmlTooltip = styled(({ className, ...other }) => <MuiTooltip {...other} classes={{ popper: className }} />)(({ theme }) => ({
  [`& .${tooltipClasses.tooltip}`]: {
    backgroundColor: '#f5f5f9',
    color: 'rgba(0, 0, 0, 0.87)',
    maxWidth: 220,
    fontSize: theme.typography.pxToRem(12),
    border: '1px solid #dadde9'
  }
}));

const CustomWidthTooltip = styled(({ className, ...other }) => <MuiTooltip {...other} classes={{ popper: className }} />)({
  [`& .${tooltipClasses.tooltip}`]: {
    maxWidth: 500
  }
});

const NoMaxWidthTooltip = styled(({ className, ...other }) => <MuiTooltip {...other} classes={{ popper: className }} />)({
  [`& .${tooltipClasses.tooltip}`]: {
    maxWidth: 'none'
  }
});

// ==============================|| PLUGIN - TOOLTIP ||============================== //

export default function Tooltip() {
  const [open, setOpen] = React.useState(false);
  const handleTooltipClose = () => {
    setOpen(false);
  };

  const handleTooltipOpen = () => {
    setOpen(true);
  };

  const longText = `
Aliquam eget finibus ante, non facilisis lectus. Sed vitae dignissim est, vel aliquam tellus.
Praesent non nunc mollis, fermentum neque at, semper arcu.
Nullam eget est sed sem iaculis gravida eget vitae justo.`;

  return (
    <Grid container spacing={gridSpacing}>
      <Grid size={{ xs: 12, md: 6, lg: 4 }}>
        <MainCard title="Simple Tooltips">
          <Stack direction="row" sx={{ gap: 1, alignItems: 'center' }}>
            <MuiTooltip title="Delete">
              <IconButton aria-label="delete" size="large">
                <DeleteIcon />
              </IconButton>
            </MuiTooltip>
            <MuiTooltip title="Add" aria-label="add">
              <Fab color="primary" sx={{ m: 2 }}>
                <AddIcon />
              </Fab>
            </MuiTooltip>
          </Stack>
        </MainCard>
      </Grid>
      <Grid size={{ xs: 12, md: 6, lg: 4 }}>
        <MainCard title="Customized Tooltip">
          <Stack direction="row" sx={{ gap: 1, alignItems: 'center' }}>
            <LightTooltip title="Add">
              <Button>Light</Button>
            </LightTooltip>
            <BootstrapTooltip title="Add">
              <Button>Bootstrap</Button>
            </BootstrapTooltip>
            <HtmlTooltip
              title={
                <>
                  <Typography sx={{ color: 'inherit' }}>Tooltip with HTML</Typography>
                  <em>And here&apos;s</em>{' '}
                  <Typography variant="subtitle1" component="span">
                    some
                  </Typography>{' '}
                  <u>amazing content</u>. it&apos;s very engaging. Right?
                </>
              }
            >
              <Button>HTML</Button>
            </HtmlTooltip>
          </Stack>
        </MainCard>
      </Grid>
      <Grid size={{ xs: 12, md: 6, lg: 4 }}>
        <MainCard title="Arrow Tooltips">
          <MuiTooltip title="Add" arrow>
            <Button>Arrow</Button>
          </MuiTooltip>
        </MainCard>
      </Grid>
      <Grid size={{ xs: 12, md: 6, lg: 4 }}>
        <MainCard title="Delay Tooltips">
          <MuiTooltip title="Add" enterDelay={500} leaveDelay={200}>
            <Button>[500ms, 200ms]</Button>
          </MuiTooltip>
        </MainCard>
      </Grid>
      <Grid size={{ xs: 12, md: 6, lg: 4 }}>
        <MainCard title="Disabled Tooltips">
          <MuiTooltip title="You Don't have permission to do this">
            <span>
              <Button disabled>A Disabled Button</Button>
            </span>
          </MuiTooltip>
        </MainCard>
      </Grid>
      <Grid size={{ xs: 12, md: 6, lg: 4 }}>
        <MainCard title="Disable Interactive Tooltips">
          <MuiTooltip title="Add" disableInteractive>
            <Button>Disable Interactive</Button>
          </MuiTooltip>
        </MainCard>
      </Grid>
      <Grid size={12}>
        <MainCard title="Triggers/Controlled Tooltips">
          <Stack direction="row" sx={{ gap: 1, alignItems: 'center' }}>
            <MuiTooltip disableFocusListener title="Add">
              <Button>Hover or touch</Button>
            </MuiTooltip>
            <MuiTooltip disableFocusListener disableTouchListener title="Add">
              <Button>Hover</Button>
            </MuiTooltip>
            <ClickAwayListener onClickAway={handleTooltipClose}>
              <div>
                <MuiTooltip
                  onClose={handleTooltipClose}
                  open={open}
                  disableFocusListener
                  disableHoverListener
                  disableTouchListener
                  title="Add"
                  slotProps={{ popper: { disablePortal: true } }}
                >
                  <Button onClick={handleTooltipOpen}>Click</Button>
                </MuiTooltip>
              </div>
            </ClickAwayListener>
          </Stack>
        </MainCard>
      </Grid>
      <Grid size={12}>
        <MainCard title="Transitions Tooltips">
          <Stack direction="row" sx={{ gap: 1, alignItems: 'center' }}>
            <MuiTooltip title="Add">
              <Button>Grow</Button>
            </MuiTooltip>
            <MuiTooltip title="Add" slots={{ transition: Fade }} slotProps={{ transition: { timeout: 600 } }}>
              <Button>Fade</Button>
            </MuiTooltip>
            <MuiTooltip title="Add" slots={{ transition: Zoom }}>
              <Button>Zoom</Button>
            </MuiTooltip>
          </Stack>
        </MainCard>
      </Grid>
      <Grid size={12}>
        <MainCard title="Variable Width Tooltips">
          <Stack direction="row" sx={{ gap: 1, alignItems: 'center' }}>
            <MuiTooltip title={longText}>
              <Button sx={{ m: 1 }}>Default Width [300px]</Button>
            </MuiTooltip>
            <CustomWidthTooltip title={longText}>
              <Button sx={{ m: 1 }}>Custom Width [500px]</Button>
            </CustomWidthTooltip>
            <NoMaxWidthTooltip title={longText}>
              <Button sx={{ m: 1 }}>No wrapping</Button>
            </NoMaxWidthTooltip>
          </Stack>
        </MainCard>
      </Grid>
      <Grid size={12}>
        <MainCard title="Positioned Tooltips">
          <Stack direction="row" sx={{ justifyContent: 'center' }}>
            <MuiTooltip title="Add" placement="top-start">
              <Button>top-start</Button>
            </MuiTooltip>
            <MuiTooltip title="Add" placement="top">
              <Button>top</Button>
            </MuiTooltip>
            <MuiTooltip title="Add" placement="top-end">
              <Button>top-end</Button>
            </MuiTooltip>
          </Stack>

          <Grid container sx={{ justifyContent: 'center' }}>
            <Grid size={6}>
              <MuiTooltip title="Add" placement="left-start">
                <Button>left-start</Button>
              </MuiTooltip>
              <br />
              <MuiTooltip title="Add" placement="left">
                <Button>left</Button>
              </MuiTooltip>
              <br />
              <MuiTooltip title="Add" placement="left-end">
                <Button>left-end</Button>
              </MuiTooltip>
            </Grid>
            <Grid container direction="column" sx={{ alignItems: 'flex-end' }} size={6}>
              <MuiTooltip title="Add" placement="right-start">
                <Button>right-start</Button>
              </MuiTooltip>
              <MuiTooltip title="Add" placement="right">
                <Button>right</Button>
              </MuiTooltip>
              <MuiTooltip title="Add" placement="right-end">
                <Button>right-end</Button>
              </MuiTooltip>
            </Grid>
          </Grid>
          <Grid container sx={{ justifyContent: 'center' }}>
            <MuiTooltip title="Add" placement="bottom-start">
              <Button>bottom-start</Button>
            </MuiTooltip>
            <MuiTooltip title="Add" placement="bottom">
              <Button>bottom</Button>
            </MuiTooltip>
            <MuiTooltip title="Add" placement="bottom-end">
              <Button>bottom-end</Button>
            </MuiTooltip>
          </Grid>
        </MainCard>
      </Grid>
    </Grid>
  );
}
